def transform_step_data(step_data):
    """
    Transforms a step's data by evaluating its expression field against input_data.

    Args:
        step_data (dict): A dictionary containing 'expression' and 'input_data' keys.

    Returns:
        dict: The transformed step data with the result of the expression.

    Raises:
        ValueError: If the expression is invalid or unsafe.
        KeyError: If required keys are missing.
    """
    if 'expression' not in step_data:
        raise KeyError("Missing 'expression' key in step_data")

    if 'input_data' not in step_data:
        raise KeyError("Missing 'input_data' key in step_data")

    expression = step_data['expression']
    input_data = step_data['input_data']

    try:
        # Parse the expression into an AST
        tree = ast.parse(expression, mode='eval')

        # Validate and sanitize the AST
        transformer = SafeTransformer()
        sanitized_tree = transformer.visit(tree)

        # Compile the sanitized AST
        code = compile(sanitized_tree, '<string>', 'eval')

        # Evaluate the expression with input_data in a restricted environment
        result = eval(code, {'__builtins__': {}}, {'input_data': input_data})

        # Return the transformed step data with the result
        return {
            'result': result,
            'original_expression': expression,
            'input_data': input_data
        }

    except SyntaxError as e:
        raise ValueError(f"Invalid expression syntax: {e}")
    except ValueError as e:
        raise ValueError(f"Unsafe or invalid expression: {e}")
    except Exception as e:
        raise ValueError(f"Error evaluating expression: {e}")

